// // This module implements a 4-to-1 multiplexer with an enable signal. It selects one of the four input data lines based on the 2-bit select line and outputs zero when the enable signal is low.
module mux_4_to_1 (
    input wire [3:0] data_in,
    input wire [1:0] sel,
    input wire enable,
    output reg data_out
);
    always @(*) begin
        if (enable) begin
            case (sel)
                2'b00: data_out = data_in[0];
                2'b01: data_out = data_in[1];
                2'b10: data_out = data_in[2];
                2'b11: data_out = data_in[3];
                default: data_out = 1'b0; // default case
            endcase
        end else begin
            data_out = 1'b0; // output zero if enable is low
        end
    end
endmodule
